 type reloader struct {
 	name     string
 	reloader func(*config.Config) error
 }
+
+type transactionalReloadManager struct {
+	mu            sync.RWMutex
+	stateFile     string
+	logger        *slog.Logger
+	lastKnownGood *config.Config
+	last          web.ReloadStatus
+}
+
+func newTransactionalReloadManager(stateFile string, logger *slog.Logger) *transactionalReloadManager {
+	m := &transactionalReloadManager{
+		stateFile: stateFile,
+		logger:    logger,
+		last: web.ReloadStatus{
+			AppliedReloaders:  []string{},
+			ReloaderTimingsMS: map[string]int64{},
+			ErrorCategory:     "none",
+		},
+	}
+	b, err := os.ReadFile(stateFile)
+	if err != nil {
+		return m
+	}
+	var status web.ReloadStatus
+	if err := json.Unmarshal(b, &status); err != nil {
+		logger.Warn("Ignoring corrupt transactional reload status", "file", stateFile, "err", err)
+		return m
+	}
+	if status.AppliedReloaders == nil {
+		status.AppliedReloaders = []string{}
+	}
+	if status.ReloaderTimingsMS == nil {
+		status.ReloaderTimingsMS = map[string]int64{}
+	}
+	m.last = status
+	return m
+}
+
+func (m *transactionalReloadManager) status() web.ReloadStatus {
+	m.mu.RLock()
+	defer m.mu.RUnlock()
+	status := m.last
+	status.AppliedReloaders = append([]string(nil), m.last.AppliedReloaders...)
+	status.ReloaderTimingsMS = make(map[string]int64, len(m.last.ReloaderTimingsMS))
+	for name, timing := range m.last.ReloaderTimingsMS {
+		status.ReloaderTimingsMS[name] = timing
+	}
+	return status
+}
+
+func (m *transactionalReloadManager) setLastKnownGood(conf *config.Config) {
+	m.mu.Lock()
+	defer m.mu.Unlock()
+	m.lastKnownGood = conf
+}
+
+func (m *transactionalReloadManager) persistLocked() {
+	b, err := json.Marshal(m.last)
+	if err != nil {
+		m.logger.Error("Failed to marshal transactional reload status", "err", err)
+		return
+	}
+	if err := os.MkdirAll(filepath.Dir(m.stateFile), 0o755); err != nil {
+		m.logger.Error("Failed to create transactional reload status directory", "err", err)
+		return
+	}
+	tmp := m.stateFile + ".tmp"
+	if err := os.WriteFile(tmp, b, 0o644); err != nil {
+		m.logger.Error("Failed to write transactional reload status", "err", err)
+		return
+	}
+	if err := os.Rename(tmp, m.stateFile); err != nil {
+		m.logger.Error("Failed to persist transactional reload status", "err", err)
+	}
+}
+
+func reloadConfiguration(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), transactional *transactionalReloadManager, rls ...reloader) error {
+	if transactional == nil {
+		return reloadConfig(filename, enableExemplarStorage, logger, noStepSubqueryInterval, callback, rls...)
+	}
+	return transactional.reload(filename, enableExemplarStorage, logger, noStepSubqueryInterval, callback, rls...)
+}
+
+func (m *transactionalReloadManager) reload(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), rls ...reloader) (err error) {
+	m.mu.Lock()
+	defer m.mu.Unlock()
+
+	status := web.ReloadStatus{LastReloadID: time.Now().UTC().Format(time.RFC3339Nano), AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]int64{}, ErrorCategory: "none"}
+	defer func() {
+		status.LastReloadSuccessful = err == nil
+		m.last = status
+		m.persistLocked()
+		callback(err == nil)
+	}()
+
+	conf, err := config.LoadFile(filename, agentMode, logger)
+	if err != nil {
+		status.ErrorCategory = "load_error"
+		status.ErrorMessage = fmt.Sprintf("couldn't load configuration (--config.file=%q): %v", filename, err)
+		return errors.New(status.ErrorMessage)
+	}
+	if enableExemplarStorage && conf.StorageConfig.ExemplarsConfig == nil {
+		conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
+	}
+
+	for _, rl := range rls {
+		start := time.Now()
+		err := rl.reloader(conf)
+		status.ReloaderTimingsMS[rl.name] = durationToInt64Millis(time.Since(start))
+		if err == nil {
+			status.AppliedReloaders = append(status.AppliedReloaders, rl.name)
+			continue
+		}
+		status.ErrorCategory = "apply_error"
+		status.ErrorMessage = err.Error()
+		status.FailedReloader = rl.name
+		if len(status.AppliedReloaders) > 0 && m.lastKnownGood != nil {
+			status.RollbackAttempted = true
+			status.RollbackSuccessful = true
+			for _, rollback := range rls {
+				if rollbackErr := rollback.reloader(m.lastKnownGood); rollbackErr != nil {
+					status.RollbackSuccessful = false
+					status.ErrorCategory = "rollback_error"
+					status.ErrorMessage = fmt.Sprintf("rollback after %s failed in %s: %v", rl.name, rollback.name, rollbackErr)
+					break
+				}
+			}
+		}
+		return fmt.Errorf("failed to apply configuration in reloader %q: %w", rl.name, err)
+	}
+
+	m.lastKnownGood = conf
+	updateGoGC(conf, logger)
+	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
+	return nil
+}

